PUT _ilm/policy/observability-retention
{
  "policy": {
    "phases": {
      "hot": {
        "min_age": "0ms",
        "actions": {
          "rollover": {
            "max_age": "7d",
            "max_primary_shard_size": "50gb"
          },
          "set_priority": { "priority": 100 }
        }
      },
      "warm": {
        "min_age": "7d",
        "actions": {
          "allocate": { "require": { "data": "warm" } },
          "forcemerge": { "max_num_segments": 1 },
          "shrink": { "number_of_shards": 1 },
          "set_priority": { "priority": 50 }
        }
      },
      "cold": {
        "min_age": "30d",
        "actions": {
          "searchable_snapshot": {
            "snapshot_repository": "s3-observability-repo"
          },
          "set_priority": { "priority": 0 }
        }
      },
      "frozen": {
        "min_age": "90d",
        "actions": {
          "searchable_snapshot": {
            "snapshot_repository": "s3-glacier-repo",
            "force_merge_index": true
          }
        }
      },
      "delete": {
        "min_age": "365d",
        "actions": {
          "delete": {
            "delete_searchable_snapshot": true
          }
        }
      }
    }
  }
}

// S3 lifecycle policy — applied to loki-chunks and tempo-traces buckets
{
  "Rules": [
    {
      "ID": "observability-tiering",
      "Status": "Enabled",
      "Filter": { "Prefix": "" },
      "Transitions": [
        { "Days": 30,  "StorageClass": "STANDARD_IA"   },
        { "Days": 90,  "StorageClass": "GLACIER_IR"     },
        { "Days": 365, "StorageClass": "DEEP_ARCHIVE"   }
      ],
      "Expiration": { "Days": 2555 }
    },
    {
      "ID": "debug-logs-short",
      "Status": "Enabled",
      "Filter": { "Prefix": "loki-chunks/debug/" },
      "Expiration": { "Days": 14 }
    }
  ]
}
